SELECT name, danceability
FROM songs
WHERE danceability > (SELECT AVG(danceability) FROM songs);

SELECT AVG(rating) AS average_starlight
FROM user_ratings
WHERE user_id = 0;

SELECT AVG(popularity) 
FROM songs 
WHERE explicit = 0;

SELECT COUNT(DISTINCT genre) 
FROM artist_genres 
WHERE artist_id = 0;
